SELECT category_id, COUNT(request_id) AS request_count
FROM request_categories
GROUP BY category_id;

SELECT relationship_type, role, COUNT(*) as user_count
FROM requests_users
GROUP BY relationship_type, role;

SELECT AVG(request_count) AS average_requests_per_user
FROM (
  SELECT user_id, COUNT(request_id) AS request_count
  FROM requests_users
  GROUP BY user_id
);

SELECT type_name, COUNT(*) AS request_type_count
FROM request_types
GROUP BY type_name;
